#include <bits/stdc++.h>
using namespace std;

const int N=3003;

struct Node{
    int l,r;
}a[N];

bool operator<(Node x,Node y){
    return x.l>y.l;
}

int n,m,s[N],cnt[N],ans;

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&a[i].l,&a[i].r);
    for(int i=1;i<=m;i++)
        scanf("%d%d",&s[i],&cnt[i]);
    sort(a+1,a+n+1);
    for(int i=1;i<=n;i++){
        int p=0;
        for(int j=1;j<=m;j++)
            if(cnt[j] && a[i].l<=s[j] && s[j]<=a[i].r && s[j]>s[p])
                p=j;
        if(p)
            cnt[p]--,ans++;
    }
    printf("%d",ans);
    return 0;
}
